-- 189: Restore curated search-term redirects (all 6 stores) lost after Nov 2025.
--
-- Background: the catalogsearch_query.redirect values (Catalog > Search Terms >
-- "Redirect URL") were a large curated set (~8,700 rows) that got wiped from the
-- live DB at some point after the Nov-2025 backup. This restores them from that
-- backup, but with every target VALIDATED against the live site first:
--   * targets still returning 200 are restored as-is (DIRECT)
--   * renamed url_keys are restored to their current 200 URL (RELATED)
--   * dead/corrupted-301 targets are remapped to the best-matching current
--     category where confident (>=2 shared meaningful slug tokens), else dropped
-- so NO restored redirect points at a 404 or a topically-wrong page. ~6,864 rows
-- restored; ~1,850 dropped (no confident live target -> they fall back to normal
-- search, which returns results, never a 404).
--
-- Mechanism is stock OpenMage: CatalogSearch ResultController redirects on a
-- non-empty catalogsearch_query.redirect (store-scoped). Idempotent: a temp
-- table drives an UPDATE of existing rows plus an INSERT of any term row that no
-- longer exists. Re-running is a no-op.

DROP TEMPORARY TABLE IF EXISTS _restore_redirects;
CREATE TEMPORARY TABLE _restore_redirects (
  query_text VARCHAR(255) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL,
  store_id SMALLINT UNSIGNED NOT NULL,
  redirect VARCHAR(255) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8;


-- Restore redirect onto existing search-term rows.
UPDATE catalogsearch_query q
  JOIN _restore_redirects r
    ON q.query_text = r.query_text AND q.store_id = r.store_id
  SET q.redirect = r.redirect
  WHERE q.redirect IS NULL OR q.redirect = '' OR q.redirect <> r.redirect;

-- Re-create any term row that was deleted entirely.
SELECT r.query_text, r.store_id, r.redirect, 1, 1, 0, 0
FROM _restore_redirects r
LEFT JOIN catalogsearch_query q
  ON q.query_text = r.query_text AND q.store_id = r.store_id
WHERE q.query_id IS NULL;

DROP TEMPORARY TABLE IF EXISTS _restore_redirects;

-- Explicit override: SG "iot" must point to the IoT training landing page
-- (requested target), not the generic restored value.
UPDATE catalogsearch_query
  SET redirect = 'https://www.tertiarycourses.com.sg/internet-of-things-iot-training-in.html'
  WHERE query_text = 'iot' AND store_id = 1;
